module RefModule(
    output Z,
    input A,
    input B,
    input EN
);wire nand1_out;
    wire nand2_out;
    wire and_out;

    // Implement NAND1 gate
    wire __nand1_out_tmp = ~(A & B);
    assign nand1_out = __nand1_out_tmp;

    // Implement NAND2 gate
    assign nand2_out = ~(nand1_out & EN);

    // Implement AND gate
    assign and_out = A & B;

    // Implement final output
    assign Z = nand2_out & and_out;

endmodule
